import requests
import json
from retry.api import retry_call
from typing import Dict,Tuple,Any
from option import Result,Ok,Err
# Helper class
class Text(object):
    def __init__(self,**kwargs):
        workerId = kwargs.get("workerId")
        self.text = json.dumps({"workerId":workerId})

"""
Description: A dummy manager is generated for when testing manually
"""
class DumbRoryManager(object):
    def __init__(self):
        pass
        
    def sendRoryRequest(self,**kwargs):
        return Text(workerId = kwargs.get("workerId","localhost"))
        
"""
Description: 
    Class that allows the connection between the client and the manager
Attributes: 
    hostname, port
    available ports:
        Client  -> 3000-5999
        Manager -> 6000-8999
        Workers -> 9000+
"""
class RoryManager(object):
    def __init__(self,**kwargs):
        self.hostname      = kwargs.get("hostname","localhost")
        self.port          = kwargs.get("port",6000)
        self.protocol      = kwargs.get("protocol","http")
        self.apiVersion    = kwargs.get("apiVersion",2)
        
        # <protocol>://<hostname|ip>:<port>
        self.baseUrl       = "{}://{}:{}".format(self.protocol,self.hostname,self.port)
        self.clusteringURL = "{}/clustering/secure".format(self.baseUrl)
        
    
    """
    Description:
        Function that allows sending the data with the request 
    Notes:
        serialize(): convert a value to a sequence of bits to be transmitted across a network.
    """
    def __get_worker(self,headers:Dict[str,str]):
        try:
            response = requests.get(
                self.clusteringURL,
                headers= {
                    "Content-Type":"application/json",**headers
                }
            )
            return response
        except Exception as e:
            raise e
    def getWorker(self,**kwargs)->Result[Tuple[str,int],Exception]:
        try:
            headers        = kwargs.get("headers")
            res            = retry_call(self.__get_worker, fkwargs={"headers":headers} ,tries=100, delay=1, max_delay=3, jitter=0.3)
            res.raise_for_status()
            stringResponse = res.content.decode("utf-8") #Decode the manager's response
            jsonResponse   = json.loads(stringResponse) # Pass the response to json
            return Ok((jsonResponse["worker_id"],jsonResponse["worker_port"]))
        except Exception as e:
            return Err(e)
